-- 1) פקודה חוקית (correct = ב, index 1)
UPDATE orders
SET
  official_definition_he = 'פקודה חוקית היא הוראה שניתנה בסמכות, תואמת את הדין ואת פקודות הצבא, וניתנת לביצוע במסגרת הנהלים. בפקודה חוקית אתה נדרש לבצע במקצועיות ועל פי הפקודות ועל פי רוחן.',
  red_flags_json = '[]'::jsonb,
  what_to_do_steps_json = '["מוודא שהבנת מה נדרש, מה גבול הביצוע, ומה נחשב סיום.", "אם יש נקודת אי בהירות שמשנה גבול - שואל שאלה קצרה לפני שאתה חוצה אותו.", "מבצע את מה שברור ומותר, ומדווח בסיום לפי הנדרש."]'::jsonb,
  mini_scenario_he = 'אתה מקבל הנחיה לבצע פעולה שגרתית. הכול נשמע תקין, אבל חסר פרט שמגדיר גבול: מה בדיוק נחשב חריגה ומה נחשב ביצוע נכון. יש לחץ זמן והצוות כבר מתקדם.

מה אתה עושה?',
  mini_choices_json = '["עוצר הכול עד שמקבל הסבר מלא לכל הפרטים, גם אם זה עוצר את הקצב לגמרי.", "מתחיל לבצע רק את מה שברור ובטוח, ושואל שאלה אחת קצרה שמגדירה את הגבול לפני שאתה ממשיך לחלק הלא ברור.", "מתחיל לבצע לפי מה שנראה לך הגיוני, כדי לא לעכב, ומתכנן לדייק אחר כך."]'::jsonb,
  mini_correct_index = 1,
  mini_feedback_json = '[{"choice_index": 0, "title": "לא מדויק", "text": "זה נשמע אחראי, אבל זו עצירה מוחלטת כשאפשר להתקדם בצורה בטוחה ומסודרת עם דיוק ממוקד."}, {"choice_index": 1, "title": "נכון!", "text": "זו משמעת חכמה: אתה מתקדם במה שברור, ומדייק גבול לפני שאתה חוצה אותו."}, {"choice_index": 2, "title": "לא מדויק", "text": "זה נשמע יעיל, אבל אתה מהמר על גבול. בפקודה חוקית אתה מבצע נכון, לא מנחש ואז מקווה שלא תהיה בעיה."}]'::jsonb
WHERE type = 'legal';

-- 2) פקודה בלתי חוקית (correct = ג, index 2)
UPDATE orders
SET
  official_definition_he = 'פקודה בלתי חוקית היא הוראה שסותרת חוק או פקודות הצבא, ולכן אינה תקינה מבחינה משפטית. ברוב המקרים האי חוקיות שלה לא גלויה כמו קו אדום ברור, ולכן ההתמודדות איתה היא בשני שלבים: אתה מבצע כדי לא לשבור מסגרת, ואז מעלה את הבעיה בצורה מסודרת מיד אחרי הביצוע. אם במהלך הביצוע מתברר שמדובר בפקודה בלתי חוקית בעליל - אתה עוצר ולא מבצע, ופועל לפי הנהלים.',
  red_flags_json = '["מבקשים ממך לחרוג מנוהל או פקודה מוכרת בלי הצדקה ברורה, ומציגים את זה כקיצור דרך.", "מבקשים ממך לשנות דיווח, להשמיט פרט מהותי, או לנסח כך שהתמונה תיראה תקינה יותר ממה שהייתה.", "אומרים לך לסמן שבוצע למרות שלא בוצע, או להשלים אחר כך בלי לוודא שזה באמת יקרה.", "מפעילים לחץ לבצע בלי אפשרות לשאול שאלה אחת שמגדירה גבול וסיכון, ומסמנים שאלות כהפרעה.", "מציעים נורמה כמו כולם עושים, לא צריך להיכנס לזה, נסדר אחר כך - במקום הנחיה מסודרת וברורה."]'::jsonb,
  what_to_do_steps_json = '["בודק מהר עם עצמך: זה קו אדום ברור, או שזה מצב בעייתי אבל לא בעליל.", "אם זה לא בעליל - מבצע לפי ההנחיה עכשיו כדי לא לשבור מסגרת, ואז מעלה מיד אחרי הביצוע בצורה עניינית ומסודרת לגורם מוסמך.", "אם זה כן בעליל - לא מבצע, עוצר ומעלה מיד לפי הנהלים.", "מתעד עובדות בצורה נקייה ומדויקת: מה נאמר, מה בוצע, מה ביקשו לשנות - בלי פרשנות ובלי האשמות.", "מבקש הנחיה ברורה להמשך כדי שהמצב לא יחזור כנורמה."]'::jsonb,
  mini_scenario_he = 'אומרים לך לבצע משהו שנראה לך בעייתי מול נהלים, אבל זה לא נראה כמו קו אדום ברור. מי שנותן את ההנחיה אומר שאין זמן ושתעלה את זה אחר כך.

מה אתה עושה?',
  mini_choices_json = '["מבצע גרסה משלך שנראית לך יותר תקינה, בלי לומר כלום, כדי לצאת גם מבצע וגם צודק.", "מסרב לבצע עד שמישהו מעליך יאשר בכתב, כי אתה לא מוכן לקחת סיכון.", "מבצע לפי ההנחיה כרגע, ואז מיד אחרי הביצוע מעלה בצורה מסודרת לגורם מוסמך את הבעיה ומבקש בדיקה והנחיה להמשך."]'::jsonb,
  mini_correct_index = 2,
  mini_feedback_json = '[{"choice_index": 0, "title": "לא מדויק", "text": "זה נראה חכם, אבל זו פעולה עצמאית שמחליפה סמכות ועלולה לייצר גם חריגה וגם חוסר אמינות."}, {"choice_index": 1, "title": "לא מדויק", "text": "זה נשמע זהיר, אבל זו הימנעות במקום פעולה. במצב שאינו בעליל, אתה מבצע ואז מערער בצורה מסודרת."}, {"choice_index": 2, "title": "נכון!", "text": "אתה פועל לפי העיקרון: מבצע כדי לא לשבור מסגרת, ואז מעלה מיד ובצורה מסודרת כדי לתקן להמשך."}]'::jsonb
WHERE type = 'illegal';

-- 3) פקודה בלתי חוקית בעליל (correct = א, index 0)
UPDATE orders
SET
  official_definition_he = 'פקודה בלתי חוקית בעליל היא הוראה שהאי חוקיות שלה גלויה וברורה לכל אדם סביר. זו פקודה שחוצה קו אדום של חוק ומוסר, בדרך כלל כשהיא דורשת פגיעה חמורה ומכוונת באדם או פעולה שהיא בבירור עבירה. במקרה כזה אסור לבצע, גם לא חלקית, ועוצרים ומעלים מיד לפי הנהלים.',
  red_flags_json = '["הוראה שמבקשת לפגוע באדם חסר אונים או להשפיל אותו בצורה חמורה.", "הוראה שנשמעת כמו עבירה ברורה, בלי קשר ללחץ או לסמכות.", "ניסוח כמו אין שאלות, אין תיעוד, תבצע עכשיו.", "ניסיון לשכנע אותך שזו רק הפחדה או רק קצת."]'::jsonb,
  what_to_do_steps_json = '["לא מבצע את הפקודה.", "עוצר את ההמשך ומעלה מיד לגורם מוסמך לפי הנהלים.", "מדווח בצורה מסודרת ומדויקת."]'::jsonb,
  mini_scenario_he = 'אתה שומע הוראה לבצע פעולה שמטרתה להעניש אדם שאינו מהווה איום, בצורה שמבזה אותו ומטרתה ללמד לקח. נותן ההוראה אומר שזה "רק לכמה שניות" ושאין זמן להסברים. באותו רגע אתה מזהה שזה חוצה קו אדום ברור, אבל יש שלושה לחצים במקביל:
אתה חושש שאם תתנגד בקול, זה יתפוצץ מול כולם.
אתה רואה שמישהו אחר כבר מתחיל לזוז כדי לבצע.
אתה לא בטוח אם לעצור פיזית, או רק להודיע שאתה לא משתתף ולדווח.

מה אתה עושה?',
  mini_choices_json = '["מנסה להרוויח זמן: מבקש הבהרה, מציע חלופה מרוככת, ומקווה שבינתיים זה ירד מהפרק.", "אומר בצורה קצרה וברורה שאתה לא מבצע, עוצר את ההמשך ככל שאתה יכול בלי להסלים, ומעלה מיד לגורם מוסמך לפי הנהלים.", "לא מבצע בעצמך, אבל גם לא עוצר אחרים. מחכה שזה יקרה ואז מדווח כדי שיהיה לך תיעוד."]'::jsonb,
  mini_correct_index = 1,
  mini_feedback_json = '[{"choice_index": 0, "title": "לא מדויק", "text": "קניית זמן וחלופה מרוככת מתאימות למצב אפור. כאן זה קו אדום ברור, וכל ניסיון לעדן משאיר מרחב ביצוע במקום עצירה."}, {"choice_index": 1, "title": "נכון!", "text": "כשזה בלתי חוקי בעליל, אתה לא מבצע ולא נותן לזה להתקדם. אתה עוצר ככל שנדרש ומעלה מיד לפי הנהלים."}, {"choice_index": 2, "title": "לא מדויק", "text": "אי השתתפות אישית לא מספיקה אם אתה יכול לעצור קו אדום ברור. לחכות ואז לדווח משאיר את הפגיעה מתרחשת בזמן אמת."}]'::jsonb
WHERE type = 'manifestly_illegal';
